import { getYouTubeVideos } from "@/lib/youtube";

export default async function LivePage() {
  const videos = await getYouTubeVideos();
  const isLive = videos.some((v) => v.liveBroadcastContent === "live");

  return (
    <main
      style={{
        background: "#000",
        color: "#fff",
        minHeight: "100vh",
        padding: "20px",
      }}
    >
      <div style={{ maxWidth: "1400px", margin: "0 auto" }}>
        <div
          style={{
            border: "1px solid #f2c500",
            padding: "40px",
            textAlign: "center",
            marginBottom: "30px",
            background: "#111",
          }}
        >
          <h1 style={{ fontSize: "36px" }}>
            {isLive ? "LIVE 🔴" : "OFFLINE ⚫"}
          </h1>

          <div
            style={{
              marginTop: "20px",
              display: "flex",
              justifyContent: "center",
              gap: "20px",
              flexWrap: "wrap",
            }}
          >
            <a
              href="https://www.youtube.com/@corsesportdiffusion9719"
              target="_blank"
              rel="noreferrer"
              style={{
                background: "#f2c500",
                color: "#000",
                padding: "20px 50px",
                borderRadius: "10px",
                fontSize: "20px",
                fontWeight: 700,
                textDecoration: "none",
              }}
            >
              YouTube
            </a>

            <a
              href="https://www.facebook.com/Corsesportdiffusion"
              target="_blank"
              rel="noreferrer"
              style={{
                background: "#000",
                color: "#f2c500",
                border: "1px solid #f2c500",
                padding: "20px 50px",
                borderRadius: "10px",
                fontSize: "20px",
                fontWeight: 700,
                textDecoration: "none",
              }}
            >
              Facebook
            </a>
          </div>
        </div>

        {videos.length > 0 ? (
          <div
            style={{
              display: "grid",
              gridTemplateColumns: "repeat(3, 1fr)",
              gap: "15px",
            }}
          >
            {videos.slice(0, 6).map((v) => (
              <a
                key={v.id}
                href={`https://www.youtube.com/watch?v=${v.id}`}
                target="_blank"
                rel="noreferrer"
                style={{ textDecoration: "none", color: "#fff" }}
              >
                <div
                  style={{
                    background: "#111",
                    border: "1px solid #f2c500",
                    padding: "5px",
                  }}
                >
                  <img
                    src={v.thumbnail}
                    alt={v.title}
                    style={{ width: "100%", display: "block" }}
                  />
                  <div style={{ padding: "5px", fontSize: "14px" }}>
                    {v.title}
                  </div>
                </div>
              </a>
            ))}
          </div>
        ) : (
          <div
            style={{
              background: "#111",
              border: "1px solid #f2c500",
              padding: "30px",
              textAlign: "center",
              color: "#ccc",
            }}
          >
            Aucune vidéo YouTube disponible pour le moment.
          </div>
        )}
      </div>
    </main>
  );
}